import{_ as i,a,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Authentication மற்றும் Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Safety/authentication-and-login-devices.md","filePath":"ta/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"ta/Safety/authentication-and-login-devices.md"};function r(c,e,u,p,m,h){return o(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="authentication-மற்றும்-login-device-management" tabindex="-1">Authentication மற்றும் Login Device Management <a class="header-anchor" href="#authentication-மற்றும்-login-device-management" aria-label="Permalink to &quot;Authentication மற்றும் Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> மற்றும் <code>Login Device Management</code> உங்கள் ImgBed admin panel, public upload entry, WebDAV access ஆகியவற்றைப் பாதுகாக்கும்.</p><p>இந்த பக்கத்தில் access credentials அமைக்கலாம், signed-in devices பார்க்கலாம், தேவையானபோது பழைய sessions revoke செய்யலாம்.</p><h2 id="எங்கு-configure-செய்வது" tabindex="-1">எங்கு Configure செய்வது <a class="header-anchor" href="#எங்கு-configure-செய்வது" aria-label="Permalink to &quot;எங்கு Configure செய்வது&quot;">​</a></h2><p>admin panel திறந்து செல்லவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>இந்த page-ல் இரண்டு முக்கிய பகுதிகள் உள்ளன:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+i+'" alt="Authentication management" loading="lazy"></p><h2 id="authentication-management-என்ன-செய்கிறது" tabindex="-1">Authentication Management என்ன செய்கிறது <a class="header-anchor" href="#authentication-management-என்ன-செய்கிறது" aria-label="Permalink to &quot;Authentication Management என்ன செய்கிறது&quot;">​</a></h2><p>Authentication Management access credentials சேமிக்கும்.</p><p>இரண்டு வகைகள்:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication என்பது upload password.</p><p>upload password அமைத்த பிறகு regular visitors upload page பயன்படுத்துவதற்கு முன் password உள்ளிட வேண்டும். public upload page எல்லோருக்கும் திறந்திருக்க வேண்டாம் என்றால் இது உதவும்.</p><p><img src="'+a+'" alt="User login page" loading="lazy"></p><h3 id="upload-password-அமைத்தல்" tabindex="-1">Upload Password அமைத்தல் <a class="header-anchor" href="#upload-password-அமைத்தல்" aria-label="Permalink to &quot;Upload Password அமைத்தல்&quot;">​</a></h3><p>upload password configured ஆக இருந்தால்:</p><ul><li>visitors upload page பயன்படுத்த password உள்ளிட வேண்டும்.</li><li>password ஏற்றுக்கொள்ளப்பட்ட பிறகே upload கிடைக்கும்.</li><li>user-side device sessions enabled என்றால் ImgBed அந்த user-side device-ஐ record செய்யும்.</li></ul><p>upload password மாற்றினால் பழைய user-side sessions invalid ஆகும். visitors புதிய password மீண்டும் உள்ளிட வேண்டும்.</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication admin username மற்றும் password பயன்படுத்தும்.</p><p>இது admin panel-ஐ பாதுகாக்கும். production use-ல் இதை எப்போதும் configure செய்ய வேண்டும்.</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="admin-credentials-அமைத்தல்" tabindex="-1">Admin Credentials அமைத்தல் <a class="header-anchor" href="#admin-credentials-அமைத்தல்" aria-label="Permalink to &quot;Admin Credentials அமைத்தல்&quot;">​</a></h3><p>admin username மற்றும் password configured ஆக இருந்தால்:</p><ul><li>admin panel திறக்க login தேவை.</li><li>successful login ஒரு admin device record உருவாக்கும்.</li><li>Login Device Management-ல் devices review, clean up, அல்லது force offline செய்யலாம்.</li></ul><p>admin username அல்லது password மாற்றினால் பழைய admin sessions invalid ஆகும். மீண்டும் sign in செய்ய வேண்டும்.</p><h2 id="login-device-management-என்ன-செய்கிறது" tabindex="-1">Login Device Management என்ன செய்கிறது <a class="header-anchor" href="#login-device-management-என்ன-செய்கிறது" aria-label="Permalink to &quot;Login Device Management என்ன செய்கிறது&quot;">​</a></h2><p>Login Device Management signed-in devices காட்டும்.</p><p>இதன் மூலம் பார்க்கலாம்:</p><ul><li>எந்த devices admin panel அணுகின.</li><li>எந்த devices user-side upload page அணுகின.</li><li>எந்த WebDAV clients connect ஆனது.</li><li>device session இன்னும் valid உள்ளதா.</li><li>பழைய devices force offline செய்ய வேண்டுமா.</li></ul><p>page-ல் மூன்று tabs உள்ளன:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>Login Device Management மேல் பகுதியில் global cookie behavior configure செய்யலாம்.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>user-side login எத்தனை நாட்கள் active ஆக இருக்கலாம் என்பதை கட்டுப்படுத்தும்.</p><p>உதாரணமாக 14 days அமைத்தால் visitors பொதுவாக 14 நாட்களுக்குள் upload password மீண்டும் உள்ளிட வேண்டியதில்லை.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>admin login எத்தனை நாட்கள் active ஆக இருக்கலாம் என்பதை கட்டுப்படுத்தும்.</p><p>உதாரணமாக 14 days அமைத்தால் administrators பொதுவாக 14 நாட்களுக்குள் மீண்டும் sign in செய்ய வேண்டியதில்லை.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Secure mode enabled ஆக இருந்தால் browsers login cookies-ஐ HTTPS வழியாக மட்டும் அனுப்பும்.</p><p>production HTTPS sites-க்கு enable செய்யவும். local HTTP testing-க்கு enable செய்ய வேண்டாம்; இல்லையெனில் &quot;login succeeded, but refresh logs me out&quot; போன்ற behavior தோன்றலாம்.</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab admin panel-ல் sign in செய்த devices காட்டும்.</p><p>admin credentials configured ஆகி admin panel login மூலம் access செய்த பிறகே device records தோன்றும்.</p><p>ஒவ்வொரு device card காட்டக்கூடியவை:</p><ul><li>device மற்றும் browser information</li><li>first login IP</li><li>last active IP</li><li>login time</li><li>last active time</li><li>expiration time</li><li>current status</li></ul><p>அறியாத device தெரிந்தால் <code>Force Offline</code> பயன்படுத்தி invalidate செய்யவும்.</p><h2 id="clean-up-old-devices" tabindex="-1">Clean Up Old Devices <a class="header-anchor" href="#clean-up-old-devices" aria-label="Permalink to &quot;Clean Up Old Devices&quot;">​</a></h2><p><code>Clean Up Old Devices</code> current tab-ல் உள்ள பழைய login records-ஐ bulk-ஆக remove செய்கிறது.</p><p>மற்ற devices-ல் பழைய sessions இன்னும் active இருக்கலாம் என்று சந்தேகம் இருந்தால் பயன்படுத்தவும்.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> ஒரு device session-ஐ invalidate செய்கிறது.</p><p>device force offline ஆன பிறகு:</p><ul><li>Admin devices மீண்டும் sign in செய்ய வேண்டும்.</li><li>User-side devices upload password மீண்டும் உள்ளிட வேண்டும்.</li><li>WebDAV clients மீண்டும் authenticate செய்ய வேண்டும்.</li></ul><p>Expired அல்லது invalid devices-ஐயும் remove செய்யலாம்.</p><h2 id="sign-out-current-device" tabindex="-1">Sign Out Current Device <a class="header-anchor" href="#sign-out-current-device" aria-label="Permalink to &quot;Sign Out Current Device&quot;">​</a></h2><p>current device card <code>Current Device</code> என mark செய்யப்படும்.</p><p>current device-ல் sign out செய்த பிறகு:</p><ul><li>current admin session sign out ஆகும்.</li><li>current user-side session sign out ஆகும்.</li></ul><p>அந்த பகுதியை தொடர்ந்து பயன்படுத்த மீண்டும் sign in செய்ய வேண்டும்.</p>',65)])])}const b=t(d,[["render",r]]);export{f as __pageData,b as default};
